<template>
  <section>
    <loader :is-visible="isLoading"></loader>

    <!-- Task Import Header Section -->
    <div class="row">
      <div class="col-md-12 padding-t_8">
        <div class="theme-primary partition-full">
          <span class="p-name text-white">{{ $t('Import Task') }}</span>
          <span class="float-right">
            <a href="javascript:;" class="p-action-btn text-white" :title="$t('BacktoList')" @click="BacktoList">
              <em class="fa fa-angle-double-left pr-2" aria-hidden="true"></em>
              <br />{{ $t('BacktoList') }}
            </a>
          </span>
        </div>
      </div>
    </div>

    <!-- Import File Section -->

    <div class="border p-3">
      <div class="row">
        <!-- Download Sample File -->
        <div class="col-sm-12 col-lg-6">
          <div class="form-group">
            <label>{{ $t('DownloadSampleFile') }}:</label>
            <div class="input-group mb-3">
              <div class="form-control">
                <i class="fa fa-file-excel-o pr-1 text-success"></i>{{ $t('TaskSample') }}.xls
              </div>
              <div class="input-group-append downloadExpense">
                <span class="input-group-text" id="basic-addon2">
                  <a href="https://cogniterblob.blob.core.windows.net/global/SampleFiles/project/task-import-sample-file.xls"
                    download>
                    <i class="fa fa-download text-primary"></i>
                  </a>
                </span>
              </div>
            </div>
          </div>
        </div>


        
        <!-- Upload File -->
        <div class="col-sm-12 col-lg-6">
          <div class="form-group">
            <label>{{ $t('UploadaFile') }}:<span class="text-danger"></span></label>
            <div class="input-group">
              <div class="custom-file expenseFile">
                <input type="file" name='FileSrc' id='flAvatar' multiple="true" tabindex="-1" @change="setFile($event)"
                  style="position: absolute; clip: rect(0px, 0px, 0px, 0px);">
                <div class="bootstrap-filestyle input-group">
                  <input type="text" class="form-control disabled" disabled="" v-model="attachmentName" />
                  <div class="input-group-append" style="cursor:pointer;">
                    <span class="group-span-filestyle input-group-btn input-group-text bg-white" tabindex="0">
                      <label title="Click here to select a file." for='flAvatar' class="mb-0 font-weight-normal ">{{
                        $t('FileControlText') }}</label>
                    </span>
                    <span class="input-group-text border-0 bg-transparent p-0 pl-2">
                      <a href="javascript:;" class="round-icon-small btn-danger-light" title="Clear" @click="Clear"><i
                          class="fa fa-undo"></i></a>
                    </span>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>

    <!-- Dynamic Form -->
    <!-- <dynamic-form ref="validateGoal" lang="en" :schema="FormSchema" @OnSubmit="onSubmit"></dynamic-form> -->

    <!-- Buttons Section -->
    <div class="row flex-row-reverse mt-3">
      <div class="col-lg-6 text-right">
        <a href="javascript:;" class="btn btn-info mr-2" v-on:click="GlobalImport" title="Import from global task">
          <i class="fa fa-save pr-2"></i>{{ $t('Import from global task') }}
        </a>
        <a href="javascript:;" class="btn btn-success" v-on:click="UploadProjectFile" title="Import from excel file">
          <i class="fa fa-file-excel-o mr-2"></i>{{ $t('Import from excel file') }}
        </a>
      </div>
      <div class="col-lg-6">
        <div class="py-2">         
            <span class="mandatory">{{ $t("Mandatory") }}</span>          
        </div>
      </div>
    </div>
    <div class="row" v-if="expListing != null && expListing.length > 0">
      <div class="col-sm-12 col-md-12 col-lg-12 col-xl-12">
        <div class="col-12 p-0 mt-3 Search-panel" id="divassestsearch">
          <div class="heading-border">
            <h5 class="h5">
              <span>{{ $t('Microsoft') }} {{ $t('Excel') }} {{ $t('Listing') }}</span>
            </h5>
          </div>
        </div>
        <div class="listing mt-2">
          <div class="table-responsive">
            <table id="Addresslist" class="table table-bordered dt-responsive nowrap mt-0">
              <thead class="thead-bg">
                <tr>
                  <th class="text-center" style="width:50px !important;" id="nonresize">
                    <div class="custom-control custom-checkbox">
                      <input class="chkItems setcheckall custom-control-input" type="checkbox" id="chkAll"
                        name="checkbox" data-parent="no" style="display: none;" v-model="selectAll" :disabled="IsDisable"
                        @change="toggleSelectAll">
                      <label class="custom-control-label universal-custom-control-label pt-1" for="chkAll"></label>
                    </div>
                  </th>
                  <th class="text-center"><span>{{ $t('Task Name') }}</span></th>
                  <!-- <th class="text-center"><span>{{ $t('Task Rate') }}</span></th>
                  <th class="text-center"><span>{{ $t('Estimated Hours') }}</span></th>
                  <th class="text-center"><span>{{ $t('Billable') }}</span></th> -->
                  <th class="text-center"><span>{{ $t('Plan Start Date') }}</span></th>
                  <th class="text-center"><span>{{ $t('Plan End Date') }}</span></th>
                  <th class="text-center"><span>{{ $t('Parent Task') }}</span></th>
                  <th class="text-center"><span>{{ $t('Task Description') }}</span></th>
                </tr>
              </thead>
              <tbody>
                <tr v-for="(item, index) in expListing" :key="index" class="text-center">
                  <td>
                    
                    <div class="custom-control custom-checkbox">
                      <input class="chkItems setcheckall custom-control-input" type="checkbox" :id="'chkAll_' + index"
                        name="checkbox" data-parent="no" style="display: none;" :disabled="item.IsDisable" v-model="item.selected"
                        v-on:change="singleCheckBox(item)">
                      <label class="custom-control-label universal-custom-control-label pt-1"
                        :for="'chkAll_' + index"></label>
                    </div>
                 
                  </td>
                  <td>{{ item.taskName }}</td>
                  <!-- <td>{{ item.taskRate || 0 }}</td>
                  <td>{{ item.Hours || 0}}</td>
                  <td>
                    <label class="switch w70">
                      <input v-bind:checked="item.isbillable" @change="onBillableChange(item)" name="isbillable"
                        type="checkbox" />
                      <span class="slider round" style="cursor:default;">
                        <span class="slider-yes">{{ $t('Yes') }}</span>
                        <span class="slider-no">{{ $t('No') }}</span>
                      </span>
                    </label>
                  </td> -->
                  <td>{{ item.planStartDate }}</td>
                  <td>{{ item.planEndDate }}</td>
                  <td>
                    <select class="form-control text-center" v-model="item.parentTaskId">
                      <option value="" selected>Select Parent Task</option>
                      <option v-for="(parenttask, index) in parenttaskdata" :key="index" :value="parenttask">
                        {{  TruncateStr(parenttask.name,20)}}
                      </option>
                    </select>
                  </td>
                  <td>{{ item.taskDescription != '' ? item.taskDescription : '--' }}</td>
                </tr>
                <tr v-if="expListing.length == 0">
                  <td colspan="20">
                    <div class="text-center text-danger">{{
                      $t('NoRecordfound') }}</div>
                  </td>
                </tr>
              </tbody>
            </table>
          </div>
        </div>
      </div>
      <div class="col-sm-12 col-md-12 col-lg-12 col-xl-12 text-right mt-2">
        <a href="javascript:;" title="Add" v-on:click="AddBulkExcel()" class="btn btn-success"><em
            class="fa fa-plus pr-2"></em><span>{{ $t('Add') }}</span></a>
      </div>
    </div>

    <!--Excel Task Listing Section -->




    <!--Task Listing Section-->
    <div class="conversation-date heading-border">
      <span>{{ $t("Task Listing") }}</span>
    </div>
    <Form ref="form">
      <div class="container-fluid collapse show p-0" id="collapseOne1">
        <div class="listing">
          <div class="table-responsive" style="overflow: visible;">
            <table id="Addresslist" class="table table-bordered dt-responsive nowrap mt-0">
              <thead class="thead-bg">
                <tr>
                  <th class="text-center"><span>{{ $t('Task Name') }}</span></th>
                  <!-- <th class="text-center"><span>{{ $t('Task Rate') }}</span></th>
                  <th class="text-center"><span>{{ $t('Hours') }}</span></th>
                  <th class="text-center"><span>{{ $t('Billable') }}</span></th> -->
                  <th class="text-center"><span>{{ $t('Plan Start Date') }}</span></th>
                  <th class="text-center"><span>{{ $t('Plan End Date') }}</span></th>
                  <th class="text-center"><span>{{ $t('parenttaskname') }}</span></th>
                  <th class="text-center"><span>{{ $t('Task Description') }}</span></th>
                  <th class="text-center"><span>{{ $t('Action') }}</span></th>
                  <!-- <th class="text-center" style="width: 170px;"><span>{{ $t('Weightage (%)') }}</span></th> -->
                </tr>
              </thead>
              <tbody>
                <tr v-for="(item, index) in ListingData" :key="index" class="text-center">
                  <td>
                    <Field :name="+ index + ' Name'" :rules="{ required: true }" v-slot="{ errors }">
                <input
                  type="text"
                  v-model="item.TaskName"
                  class="form-control"
                  :class="[
                    'form-control',
                    { 
                      'is-invalid': errors.length > 0 || item.isDuplicate 
                    }
                  ]"
                />
              </Field>
                  </td>
                  <!-- Plan Start Date -->
                    <td style="overflow:visible!important;">
            <Field :name="+ index +`planned_start_date`" :rules="{ required: true }" v-slot="{ errors }">
                  <v-date-picker
                    v-model="item.PlanStartDate"
                    :min-date="StartDate"
                    :max-date="EndDate"
                    :format="'DD/MM/YYYY'"
                    class="input-group"
                  >
                <template v-slot="{ inputValue, togglePopover }">
                  <input
                    placeholder="DD/MM/YYYY"
                    :value="inputValue"
                    class="form-control"
                    :class="{ 'is-invalid': errors.length > 0 }"
                    readonly
                  />
                  <div class="input-group-append" @click="togglePopover()" style="cursor: pointer">
                    <span class="input-group-text">
                      <em class="fa fa-calendar"></em>
                    </span>
                  </div>
                </template>
              </v-date-picker>
            </Field>
          </td>



              <!-- Plan End Date -->
              <td style="overflow:visible!important;">
                <Field :name="+ index +`planned_end_date`" :rules="{ required: true }" v-slot="{ errors }">
                  <v-date-picker
                    v-model="item.PlanEndDate"
                    :min-date="item.PlanStartDate"
                    :max-date="EndDate"
                    :format="'DD/MM/YYYY'"
                    class="input-group"
                  >
                    <template v-slot="{ inputValue, togglePopover }">
                      <input
                        placeholder="DD/MM/YYYY"
                        :value="inputValue"
                        class="form-control"
                        :class="{ 'is-invalid': errors.length > 0 }"
                        readonly
                      />
                      <div class="input-group-append" @click="togglePopover()" style="cursor: pointer">
                        <span class="input-group-text">
                          <em class="fa fa-calendar"></em>
                        </span>
                      </div>
                    </template>
                  </v-date-picker>
                </Field>
              </td>

              <td>
                    <Field :name="+ index + 'ParentTaskName'"  v-slot="{  errors }">
                      <input type="text" class="form-control" v-model="item.ParentTaskName" 
                        :class="['form-control disabled']" />
                    </Field>
                  </td>
                    <!-- Task Description -->
                  <td>
                    <Field :name="+ index + 'Description'" :rules="{ required: true }" v-slot="{  errors }">
                      <input type="text" class="form-control" v-model="item.TaskDescription"
                        :class="['form-control', { 'is-invalid': errors.length > 0 }]" />
                    </Field>
                  </td>
                
                    <td class="single-action">
                       <a href="javascript:void(0);"  v-on:click="DeleteTaskItem(item, index)">
                           <em class="fa fa-trash  text-danger"></em>
                       </a>
                   </td>
                   </tr>
                <tr v-if="ListingData.length === 0">
                  <td colspan="20" class="text-center text-danger">
                    {{ $t('NoRecordfound') }}
                  </td>
                </tr>
              </tbody>
            </table>
          </div>
          <div class="row flex-row-reverse mt-3">
            <div class="col-lg-6 text-right">
              <a href="javascript:;" title="Save" class="btn btn-success mr-1" v-on:click="OnSubmit()"><em class="fa fa-save pr-2"></em>{{ $t('Save') }}</a>
              <a href="javascript:;" title="AddMore" id="addMore" v-on:click="AddMore()" class="btn btn-info mr-1"><em class="fa fa-plus pr-2"></em>{{ $t('AddMore') }}</a>
              <a href="javascript:;" title="Cancel" class="btn btn-danger" v-on:click="RedirectToProjectDetails()"><em class="fa fa-close pr-2"></em>{{ $t('Cancel') }}</a>
            </div>
          </div>
        </div>
      </div>

    </Form>

    <!--Open Team Model-->
    <AddTeam v-if="IsAssignedUser" :ProjectId="projectId" :TaskId="ParentTaskId" :Type="IsType"
      :ProjectName="ProjectName" @close="IsAssignedUser = false;" @callbackfunction="FetchTaskList"></AddTeam>
    <GlobalTask v-if="isGlobalTask" :projectId="projectId" @cancel="Cancel" @next="selectedGlobalTeask">
    </GlobalTask>
    <AllowTime v-if="IsAllowTime"  :projectId="projectId" :taskId="TaskId" @cancel="Cancel"></AllowTime>
  </section>
</template>

<script>
import GlobalTask from '../../../../components/Modal/GlobalTask.vue';
import DataService from '../../../../services/DataService.js';
import AddTeam from '../../../../components/Modal/AddTeam.vue';
import AllowTime from '../../../../components/Modal/AllowTime.vue';
export default {
  components: { GlobalTask, AddTeam,AllowTime },
  props: {
    UserId: {
      type: Number,
      required: false
    },
    GoalId: {
      type: Number,
      required: false
    },
    callbackfunction: {
      type: Function
    },
    GoalType: {
      type: String,
      required: false
    },
    GoalArray: {
      type: Array,
      required: false
    },
    projectId: {
      type: Number,
      required: false
    }
  },
  data() {

    return {
      projectId: 0,
      IsType: 'task',
      proficiencyManager: 0,
      noRecord: false,
      TotalRecords: 0,
      isLoading: false,
      CommentList: [],
      weightagePersent: 0,
      progress: 0,
      startDate: '',
      endDate: '',
      isGlobalTask: false,
      ProficiencyHistoryList: [],
      attachmentName: '',
      oldattachmentName:'',
      file: '',
      excelFileName: '',
      filepath: '',
      expListing: [],
      ListingData: [],
      IsAssignedUser: false,
      ParentTaskId: null,
      projectHours: 0,
      PlanStartDate: '',
      PlanEndDate: '',
      selectAll: false,
      IsDisable:false,
      parenttaskdata:[],
      AllowTimeData:[],
      IsAllowTime:false,
      TaskId:0,
      taskUserdata:[],
      StartDate:'',
      EndDate:'',
      selectedTaskIds: new Set()
    }
  },
  async created() {
    this.projectId = this.$route.params.projectId;
    this.projectHours = this.$route.params.projectHours;
    this.oldattachmentName='';
    // this.FetchTaskList();
   await this.ProjectOverview();
  },
  watch: {
  items: {
    handler(newItems) {
      debugger
      newItems.forEach(item => {
        if (
          item.PlanStartDate &&
          item.PlanEndDate &&
          new Date(item.PlanEndDate) < new Date(item.PlanStartDate)
        ) {
          this.StartDate= item.PlanStartDate;
          item.PlanEndDate = item.PlanStartDate;
        }
      });
    },
    deep: true
  }
}
,
  computed: {
    groupByDate() {
      let groups = {};
      this.CommentList.forEach(item => {
        let date = item.CREATED_AT.substring(0, 10);
        if (groups[date]) {
          groups[date].push(item);
        } else {
          groups[date] = [item];
        }
      });
      return groups;
    }
  },
  methods: {
    
    DeleteTaskItem: function (item, index) {
            var vm = this;
            var msg = vm.$t("ConfirmDelete");
            vm.confirmR(msg, true, null,
                function () {
                    // Re-enable the task in Microsoft listing if it exists
                    if (vm.expListing && vm.expListing.length > 0) {
                        var matchingTask = vm.expListing.find(expItem => 
                            expItem.taskName && item.TaskName && 
                            expItem.taskName.trim().toLowerCase() === item.TaskName.trim().toLowerCase()
                        );
                        if (matchingTask) {
                            matchingTask.IsDisable = false;
                            matchingTask.selected = false;
                            // Update selectAll state if needed
                            const enabledTasks = vm.expListing.filter(task => !task.IsDisable);
                            if (enabledTasks.length > 0) {
                                vm.IsDisable = false;
                            }
                        }
                    }
                    vm.ListingData.splice(index, 1);
                });
        },
    ProjectOverview: async function () {
            var vm = this;
            var params = `projectId=${this.projectId}`;
            await DataService.ProjectOverview(params).then(function (response) {
              debugger
                if (response.data != null > 0) {                    
                    vm.StartDate = response.data.planneD_START_DATE;
                    vm.EndDate = response.data.planneD_END_DATE;
                }
            });
        },
    AddBulkExcel: function () {
      debugger
      var thisObj = this;
      var result = thisObj.expListing.filter(element => element.selected);
      const selectedCount = this.expListing.filter(item => item.selected).length;
      this.selectAll = selectedCount === this.expListing.length && this.expListing.length > 0;
      if(this.selectAll)
    {thisObj.IsDisable=true}
      if (result.length == 0) {
        thisObj.ShowAlert(thisObj.$t("PleaseSelectAtleastOneTask"), "warning", true, thisObj.$t("Alert"));
        return false;
      }
      result.forEach(function (element,index) {
        debugger
        element.IsDisable=true;
        element.selected =false;
        thisObj.selectAll=false;
        var sdate = element.planStartDate;
        var edate = element.planEndDate;
    var emptyItem = {
    TOTAL_RECORDS: null,
    rowlevel: "rowlevel" + index,
    PARENT_TASK_LISTS: [],
    TaskId: null,
    ProjectId: null,
    TaskName: element.taskName || null,
    TaskRate: element.taskRate != null ? String(element.taskRate) : 0,
    TaskDescription: element.taskDescription || null,
    EstimatedtaskHours: element.estimatedtaskHours != null ? element.estimatedtaskHours : null,
    Hours: element.hours != null ? String(element.hours) : 0,
    HOURSPEND: 0,
    Minutes: null,
    TaskBaseRate: null,
    ProjectManagerName: null,
    Isbillable: element.isbillable != null ? Boolean(element.isbillable) : null,
    Isglobal: null,
    AssignToAllTeamMember: null,
    StatusId: "1001",
    PlanStartDate:sdate|| null,
    PlanEndDate:edate || null,
    TargetStartDate: null,
    TargetEndDate: null,
    Priorities: null,
    TaskType: null,
    TaskTypeName: null,
    PriorityName: null,
    ParentTaskId: element.parentTaskId.value != null ? String(element.parentTaskId.value) : null,
    ParentTaskName:element.parentTaskId.name != null ? String(element.parentTaskId.name) : null,
    percentageCompleted: null,
    SpentTime: null,
    duration: "",
    locationId: null,
    Weightage: "0",
    Current_Progress: null,
    Tag: "",
    Stage: "",
    Team: [],
    User_Type_Id: null,
    level: index,
    main_parent_id: null,
    IS_INCLUDE_IN_TASK: null,
    allowtimer: null,
    CAN_DELETE_TASK: null,
    pin_id: null,
    IS_SAMPLE_DATA: null,
    AssignedHours: null,
    ROWNUMBER: null,
    ChildTaskList: [],
    NOTES_COUNT: null,
    ItemIndex: index + 1,
    uniqueNumber: index + 1,
    ParentPlanStartDate: sdate || null,
    ParentPlanEndDate: edate || null,
    StageId: null,
    RefRowIndex: "RowIndex_" + (index + 1)
};
        debugger        
        thisObj.ListingData.push(emptyItem);
      })
    },
    toggleSelectAll() {
      this.expListing.forEach((item) => {
         if(item.IsDisable==false)
            {
            item.selected = this.selectAll;
            }
      });
    },
    singleCheckBox(itm) {
      const selectedCount = this.expListing.filter(item => item.selected).length;
      this.selectAll = selectedCount === this.expListing.length && this.expListing.length > 0;
    },
    onBillableChange(item) {
      var vm = this;      
      if (item.Isbillable == false) {
        item.Isbillable = true;
      }
      else {
        item.Isbillable = false;
      }
    },
    AddMore() {
      const emptyItem = {
        "TOTAL_RECORDS": 0,
        "rowlevel": "",
        "PARENT_TASK_LISTS": "",
        "TaskId": "-1",
        "ProjectId": this.projectId,
        "TaskName": "",
        "TaskRate": "",
        "TaskDescription": "",
        "EstimatedtaskHours": 0,
        "Hours": "10:00",
        "HOURSPEND": 0,
        "Minutes": 0,
        "TaskBaseRate": "",
        "ProjectManagerName": "",
        "Isbillable": false,
        "Isglobal": false,
        "AssignToAllTeamMember": null,
        "StatusId": "",
        "PlanStartDate": this.$d(new Date(this.StartDate)),
        "PlanEndDate": this.$d(new Date(this.EndDate)),
        "TargetStartDate": "",
        "TargetEndDate": "",
        "Priorities": "",
        "TaskType": "",
        "TaskTypeName": "",
        "PriorityName": "",
        "ParentTaskId": "",
        "percentageCompleted": "",
        "SpentTime": "",
        "duration": "",
        "locationId": "",
        "Weightage": "",
        "Current_Progress": 0,
        "Tag": "",
        "Stage": "",
        "Team": "",
        "level": "",
        "main_parent_id": "",
        "ROWNUMBER": 0,
        "ChildTaskList": [],
        "ItemIndex": 0,
        "uniqueNumber": 0,
        "ParentPlanStartDate": "",
        "ParentPlanEndDate": "",
        "StageId": ""
      };
      this.ListingData.push({ ...emptyItem });
    },
    Close() {
      this.$router.push({
        name: "ProjectTask",params: { projectId: this.projectId }
      });
    },
    OpenAssignedUser: function (TaskId) {
      debugger
      var vm = this;
      vm.TaskId=TaskId;
      vm.IsAllowTime=true;
    },
      BindParenttaskDropdown: function () {
      var ths = this;
      ths.parenttaskdata=[];
      var url = `id=${ths.projectId}&moduleName=PHASE_NAME&type=PARENT_TASK_DDL&search=&refId=`;
      DataService.GetDDLData(url).then((response) => {
        if (response.data.DATA.length > 0) {
          response.data.DATA.forEach((item) => {
            let obj = {
              name: item.name,
              value: item.value
            }
               ths.parenttaskdata.push(obj);
          })
        }
      })
    },
    DeleteTask: function (item, index) {
      var vm = this;
      var val = "";
      val = index;
      if (val != null) {
        vm.confirmR(vm.$t("ConfirmDelete"), true, (vm.$t("Delete") + "  " + vm.$t("Project")), function () {
          vm.ListingData.splice(index, 1);
          vm.ShowAlert(vm.$t('DeletedSuccess', [vm.$t('Task')]), "success", true, vm.$t("Alert"));
        });
      }
      else {
        vm.ShowAlert(vm.$t("Selectanyrecordtodelete"));
      }
    },
    onProgressSlide(index) {
      var vm = this;
      vm.weightagePersent = this.index;
    },
    setFile: function (e) {
      this.attachmentName = e.target.files[0].name;
      this.file = e.target.files[0];
      this.excelFileName = e.target.files[0].name;
    },
    UploadProjectFile: function () {
      var vm = this;
      debugger
      vm.IsDisable=false;
      if ($("#flAvatar").val() != "") {   
        var file = $("#flAvatar").val().split('\\').pop();
        var allowFileTypesExt = '.xls,.xlsx';
        var extension = file.replace(/^.*\./, '');
        if (!allowFileTypesExt.includes(extension)) {
          vm.ShowAlert(vm.$t('InvalidSampleFileUploadMsg', [file, allowFileTypesExt]), "warning", true, vm.$t('Alert'));
        }
        if(vm.oldattachmentName==file)
        {
          vm.ShowAlert(vm.$t('PleaseSelectDifferentFile'), "warning", true, vm.$t("Alert"));
          return;
