OnSubmit: async function () {
  var vm = this;
  debugger;
  const isValid = await this.$refs.form.validate();
  if (isValid) {
    const taskNames = vm.ListingData.map(item => (item.TaskName || '').trim().toLowerCase());
    const duplicates = taskNames.filter(
      (name, index) => taskNames.indexOf(name) !== index && name !== ''
    );
    vm.ListingData = vm.ListingData.map((item, index) => {
      const taskName = (item.TaskName || '').trim().toLowerCase();
      return {
        ...item,
        isDuplicate: duplicates.includes(taskName) && taskName !== ''
      };
    });
    if (duplicates.length > 0) {
      vm.ShowAlert(vm.$t('DuplicateTaskNameFound'), 'failure', true, vm.$t('Alert'));
      return;
    }
    // Validate Start and End Dates before saving
const invalidDate = vm.ListingData.some(item => {
  if (item.PlanStartDate && item.PlanEndDate) {
    const start = new Date(item.PlanStartDate);
    const end = new Date(item.PlanEndDate);

    start.setHours(0,0,0,0);
    end.setHours(0,0,0,0);

    return start > end;
  }
  return false;
});

if (invalidDate) {
  vm.ShowAlert(vm.$t('Enddatecannot'), "failure", true, vm.$t("Alert"));
  return;
}
    vm.isLoading = true;
    vm.ListingData = vm.ListingData.map(item => ({
      ...item,
      AssignToAllTeamMember: item.AssignToAllTeamMember ? 1 : 0
    }));
   debugger
    const postJSON = {
      ProjectId: vm.projectId,
      ProjectHours: vm.projectHours,
      MilestoneId: 0,
      taskData: vm.ListingData
    };

    const objectPostString = JSON.stringify(postJSON);

    try {
      const response = await DataService.SaveBulkUploadTask(objectPostString);
      vm.isLoading = false;
      debugger;

      if (response.data.result != null) {
        if (response.data.result == 0) {
          vm.ProjectData = response.data.result.ProjectData;
          vm.isProjectData = true;
          vm.RedirectToProjectDetails();
          vm.ShowAlert(vm.$t("AddedSuccess", [vm.$t("Task")]), "success", true, vm.$t("Alert"));
        } else if (response.data.result == -2) {
          vm.ProjectData = response.data.result.ProjectData;
          vm.isProjectData = true;
          vm.ShowAlert(vm.$t("AlreadyExists", [vm.$t("Task")]), "failure", true, vm.$t("Alert"));
        } else {
          vm.ShowAlert(vm.$t('UnknownErrorOccur'), "failure", true, vm.$t("Alert"));
        }
      }
    } catch (err) {
      vm.isLoading = false;
      console.error(err);
      vm.ShowAlert(vm.$t('UnknownErrorOccur'), "failure", true, vm.$t("Alert"));
    }

  } else {
    vm.ShowAlert(vm.$t('Please correct the highlighted errors.'), "failure", true, vm.$t("Alert"));
  }
}

